CREATE POLICY "Allow admin to update daemon status" ON public.daemon_status FOR UPDATE TO authenticated USING ( id = '00000000-0000-0000-0000-000000000000' AND EXISTS (SELECT 1 FROM public.user_profiles WHERE user_id = auth.uid() AND role = 'admin') ) WITH CHECK ( id = '00000000-0000-0000-0000-000000000000' AND EXISTS (SELECT 1 FROM public.user_profiles WHERE user_id = auth.uid() AND role = 'admin') );
CREATE POLICY "Allow admin to insert daemon status" ON public.daemon_status FOR INSERT TO authenticated WITH CHECK ( id = '00000000-0000-0000-0000-000000000000' AND EXISTS (SELECT 1 FROM public.user_profiles WHERE user_id = auth.uid() AND role = 'admin') );